"""
MKT Original — Matthew 26
Output: data/commentary/mkt-original/matthew.json (adds ch26)
"""
import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: Per-verse Greek lexical commentary for Matthew 26; covers Passion Week
#   from the Anointing through Peter\'s denial. Strictly lexical/syntactic focus.
# CHANGE? If verse keys change in data/interlinear/matthew.json, update dict keys here.
# VERIFY: Run script; confirm "wrote data/commentary/mkt-original/matthew.json".
#   Then check ch26 has 75 verses matching the interlinear.

NEW_DATA = {
  "26": {
    "1": "<p><strong>kai egeneto hote etelesen ho Iēsous pantas tous logous toutous</strong> — <em>and it came to pass when Jesus finished all these words</em> — <em>Etelesen</em> (aorist of <em>teleō</em> = to complete, finish) — the fifth and final discourse-conclusion formula in Matthew (cf. 7:28; 11:1; 13:53; 19:1). <em>Pantas tous logous toutous</em> (all these words) is emphatic — the entire eschatological discourse is now complete. What follows is the Passion narrative.</p>",
    "2": "<p><strong>meta dyo hēmeras to pascha ginetai</strong> — <em>after two days the Passover comes</em> — <em>Ginetai</em> (present tense: is coming, is happening) gives immediacy to the announcement. <em>Kai ho huios tou anthrōpou paradidotai eis to staurōthēnai</em> (and the Son of Man is betrayed to be crucified) — <em>paradidotai</em> (present passive: is being handed over) — the process is already underway. <em>Staurōthēnai</em> (aorist passive infinitive of <em>stauroō</em> = to crucify) — the manner of death is specified explicitly.</p>",
    "3": "<p><strong>tote synēchthēsan hoi archiereis kai hoi presbyteroi tou laou</strong> — <em>then the chief priests and elders of the people were gathered</em> — <em>Synēchthēsan</em> (aorist passive: were assembled) — a formal gathering of the Sanhedrin leadership. <em>Eis tēn aulēn tou archiereōs</em> (in the courtyard of the high priest) named <em>Kaiaphas</em> — the mention of the specific high priest grounds this in historical particularity.</p>",
    "4": "<p><strong>kai synebouleusanto hina ton Iēsoun dolō kratēsōsin kai apokteinōsin</strong> — <em>and they plotted to seize Jesus by stealth and kill him</em> — <em>Synebouleuō</em> (to take counsel together, deliberate) — formal deliberation. <em>Dolō</em> (by trickery, by stealth — from <em>dolos</em> = bait, snare) — the method distinguishes their plot from open confrontation. <em>Kratēsōsin</em> (aorist subjunctive of <em>krateō</em> = to seize, arrest) and <em>apokteinōsin</em> (kill) — two successive aorist subjunctives in purpose.</p>",
    "5": "<p><strong>mē en tē̄ heortē̄ hina mē thorybos genētai en tō̄ laō̧</strong> — <em>not during the feast lest there be a riot among the people</em> — <em>Thorybos</em> (uproar, riot, tumult) — the political calculation is explicit: Passover crowds in Jerusalem (estimated up to 100,000+) made public arrest dangerous. The divine irony: their precaution to avoid the feast results in the arrest happening at Passover precisely.</p>",
    "6": "<p><strong>tou de Iēsou genomēnou en Bēthania en oikia Simōnos tou leprou</strong> — <em>while Jesus was in Bethany in the house of Simon the leper</em> — <em>Genomēnou</em> (genitive absolute: while he was) — the temporal and spatial setting. <em>Simon ho lepros</em> (Simon the leper) — presumably healed; otherwise his house would be off-limits to guests and neighbors. The name is otherwise unattested in the passion story.</p>",
    "7": "<p><strong>prosēlthen autō̄ gynē echousa alabastron myrou baretimon</strong> — <em>a woman came to him having an alabaster flask of very precious ointment</em> — <em>Alabastron</em> (alabaster flask, unguentarium) = a sealed flask of polished alabaster, typically containing expensive perfume. <em>Myron barytimou</em> (precious ointment — <em>barys</em> = heavy/weighty + <em>timē</em> = price/value; of great price). <em>Katecheen epi tēs kephalēs autou</em> (poured it on his head) — anointing the head, the prophetic/royal anointing gesture.</p>",
    "8": "<p><strong>idontes de hoi mathētai ēganaktēsan legontes</strong> — <em>the disciples seeing this were indignant saying</em> — <em>Aganakteō</em> (to be indignant, grieved, angry) — the same verb used for the Twelve\xe2\x80\x99s response to the Zebedee request (20:24). <em>Eis ti hē apōleia autē</em> (for what purpose this waste?) — <em>apōleia</em> (waste, destruction, loss — the word for Judas: <em>huios tēs apōleias</em> in John 17:12) is striking applied to the ointment.</p>",
    "9": "<p><strong>edynato gar touto prathēnai pollou kai dothēnai ptōchois</strong> — <em>for this could have been sold for much and given to the poor</em> — <em>Prathēnai pollou</em> (sold for much — genitive of price) — the practical calculation is not wrong in itself; the disciples\xe2\x80\x99 error is valuing the ointment economically while missing its eschatological significance. Mark 14:5 specifies more than 300 denarii.</p>",
    "10": "<p><strong>gnous de ho Iēsous eipen autois ti kopous parechete tē̄ gynaiki</strong> — <em>Jesus knowing said: why do you cause trouble for the woman?</em> — <em>Gnous</em> (having known — divine insight into their grumbling). <em>Kopous parechete</em> (you cause trouble/burdens) — <em>kopos</em> (toil, trouble, annoyance). <em>Ergon gar kalon ērgasato eis eme</em> (for a beautiful work she has done toward me) — <em>kalon</em> (beautiful, noble, excellent) rather than merely <em>agathos</em> (good).</p>",
    "11": "<p><strong>tous ptōchous gar pantote echete meth\' heautōn</strong> — <em>for the poor you always have with you</em> — Echoes Deut 15:11 (<em>ou gar mē ekleipē̄ chreia apo tēs gēs</em>). The statement is not dismissive of the poor but establishes a temporal distinction: the poor are always present for service; Jesus\xe2\x80\x99 physical presence is not. <em>Eme de ou pantote echete</em> (but me you do not always have) — the temporal constraint governs the woman\xe2\x80\x99s action\xe2\x80\x99s appropriateness.</p>",
    "12": "<p><strong>balousa gar autē to myron touto epi tou sōmatos mou</strong> — <em>for she, pouring this ointment on my body</em> — <em>Pros to entaphiasai me epoiēsen</em> (she did it for my burial preparation) — <em>entaphiazō</em> (to prepare for burial, to entomb) — Jesus interprets the anointing as anticipatory burial unction. The woman acts prophetically without knowing it.</p>",
    "13": "<p><strong>amēn legō hymin hopou ean kērychthē̄ to euangelion touto</strong> — <em>truly I say to you wherever this gospel is proclaimed</em> — <em>Hopou ean... en holō̄ tō̄ kosmō̄</em> (wherever... in all the world) — universal scope. <em>Kai ho epoiēsen autē lalēthēsetai eis mnēmosynon autēs</em> (what she did will be spoken as a memorial of her) — <em>mnēmosynon</em> (memorial, remembrance — cf. LXX Lev 2:2 for the memorial portion of the grain offering; here applied to a person).</p>",
    "14": "<p><strong>tote poreutheis heis tōn dōdeka ho legomenos Ioudas Iskariōtēs</strong> — <em>then one of the Twelve, the one called Judas Iscariot</em> — <em>Tote</em> (then) — the anointing\xe2\x80\x99s juxtaposition with Judas\xe2\x80\x99 betrayal is deliberate. <em>Ho legomenos Ioudas Iskariōtēs</em> (the one called Judas Iscariot) — <em>Iskariōtēs</em> likely = <em>ish-Kerioth</em> (man of Kerioth, a town in Judah) — identifying him by origin.</p>",
    "15": "<p><strong>ti thelete moi dounai kagō hymin paradōsō auton</strong> — <em>what are you willing to give me and I will hand him over to you?</em> — <em>Ti thelete moi dounai</em> (what do you wish to give me?) — Judas initiates the price negotiation. <em>Hoi de estēsan autō̄ triakonta argyria</strong> (they weighed out to him thirty silver pieces) — <em>histēmi</em> (to weigh, to set, to pay) — <em>triakonta argyria</em> = thirty silver pieces, echoing Zech 11:12 (the price of a slave, Ex 21:32), the prophetic valuation of the good shepherd.</p>",
    "16": "<p><strong>kai apo tote ezētei eukairian hina auton paradō̄</strong> — <em>and from then he sought an opportune time to hand him over</em> — <em>Apo tote</em> (from then) — a structural marker (cf. 4:17; 16:21). <em>Eukairian</em> (opportune time, the right moment — from <em>eukairia</em> = good timing, <em>eu</em> + <em>kairos</em>). <em>Paradō̄</em> (aorist subjunctive of <em>paradidōmi</em> = to hand over, betray) — the passion verb.</p>",
    "17": "<p><strong>tē̄ de prōtē̄ tōn azymōn prosēlthon hoi mathētai</strong> — <em>on the first day of Unleavened Bread the disciples came</em> — <em>Azymōn</em> (unleavened bread — genitive plural of <em>azymos</em>: without yeast) — the seven-day Passover/Unleavened Bread festival. <em>Pou theleis hetoimasōmen soi phagein to pascha</em> (where do you wish we prepare for you to eat the Passover?) — the technical Passover preparations required an approved room and a slaughtered lamb.</p>",
    "18": "<p><strong>hypagete eis tēn polin pros ton deina</strong> — <em>go into the city to a certain person</em> — <em>Ton deina</em> (a certain one, so-and-so) — deliberately anonymous; Matthew may be protecting the householder\xe2\x80\x99s identity. <em>Ho kairos mou eggys estin</em> (my time is near) — <em>Kairos</em> here = appointed time, the decisive moment of fulfillment (cf. Gal 4:4). <em>Pros se poiō to pascha</em> (at your house I will keep the Passover) — future indicative of determined intention.</p>",
    "19": "<p><strong>kai epoiēsan hoi mathētai hōs synetaxen autois ho Iēsous</strong> — <em>the disciples did as Jesus directed them</em> — <em>Syntassō</em> (to arrange, direct, command) — the same verb for the disciples\xe2\x80\x99 obedience at the Triumphal Entry (21:6). The aorist <em>hetoimasan to pascha</em> (prepared the Passover) summarizes without detail.</p>",
    "20": "<p><strong>opsias de genomenes anekeito meta tōn dōdeka</strong> — <em>when evening came he reclined with the Twelve</em> — <em>Opsia</em> (evening) — the Passover meal was eaten after sunset. <em>Anekeito</em> (reclined, imperfect of <em>anakeimai</em>) — the reclining posture of the symposium/banquet; Passover was eaten reclining as a sign of freedom (not the slave\xe2\x80\x99s standing posture). <em>Meta tōn dōdeka</em> (with the Twelve) — the full inner circle.</p>",
    "21": "<p><strong>kai esthiontōn autōn eipen amēn legō hymin</strong> — <em>while they were eating he said: truly I say to you</em> — The genitive absolute <em>esthiontōn autōn</em> (while they were eating) situates the announcement mid-meal. The <em>amēn</em> solemn introduction signals the gravity of what follows: <em>heis ex hymōn paradōsei me</em> (one of you will hand me over).</p>",
    "22": "<p><strong>kai lypumenoi sphodra ērxanto legein autō̄ heis hekastos</strong> — <em>deeply grieved they began to say to him, one by one</em> — <em>Lypeomai sphodra</em> (to be deeply grieved, intensely pained) — <em>sphodra</em> (intensely, greatly). <em>Heis hekastos</em> (each one individually) — each disciple separately asks <em>mēti egō eimi kyrie</em> (surely it is not I, Lord?) — the <em>mēti</em> (particle expecting a negative answer) reveals each believes himself incapable of betrayal.</p>",
    "23": "<p><strong>ho embapsas met\' emou tēn cheira en tō̄ trybliō̧ houtos me paradōsei</strong> — <em>the one who dipped his hand with me in the dish, this one will betray me</em> — <em>Embapto</em> (to dip, immerse) in <em>tryblio</em> (a common dish, bowl) — the shared dipping of the <em>haggadah</em> sop. The identification is not narrowed to one person; many at the table would dip together. The act specifies intimate table fellowship as the context of betrayal — echoing Ps 41:9.</p>",
    "24": "<p><strong>ho men huios tou anthrōpou hypagei kathōs gegraptai peri autou</strong> — <em>the Son of Man goes as it has been written concerning him</em> — <em>Hypagō</em> (to go away) as a euphemism for going to death; <em>kathōs gegraptai</em> (as it has been written) — the divine necessity of scripture fulfillment. <em>Ouai de tō̄ anthrōpō̧ ekeinō̧ di\' hou ho huios tou anthrōpou paradidotai</em> — the woe (<em>ouai</em>) on the betrayer is juxtaposed with the divine <em>dei</em> (necessity): scripture\xe2\x80\x99s fulfillment does not absolve the agent.</p>",
    "25": "<p><strong>apokritheis de Ioudas ho paradidous auton eipen mēti egō eimi Rhabbi</strong> — <em>Judas who was betraying him answered: surely it is not I, Rabbi?</em> — Judas uses <em>Rhabbi</em> (Rabbi) while the other disciples used <em>Kyrie</em> (Lord) — the title distinction may reflect Judas\xe2\x80\x99s relationship to Jesus as teacher but not as Lord. <em>Legei autō̄ sy eipas</em> (he says to him: you have said it) — <em>sy eipas</em> (you said it) is an affirmative formula confirming the question\xe2\x80\x99s truth without a direct yes.</p>",
    "26": "<p><strong>esthiontōn de autōn labōn ho Iēsous arton</strong> — <em>while they were eating Jesus took bread</em> — The institution narrative (vv.26-29) occurs during the meal. <em>Eulogēsas eklāsen</em> (having blessed he broke) — the berakah blessing and breaking of bread. <em>Kai edōken tois mathētais kai eipen labete phagete touto estin to sōma mou</em> (took, gave to the disciples and said: take, eat; this is my body) — <em>sōma</em> (body) without qualifier; the identification is direct.</p>",
    "27": "<p><strong>kai labōn potērion kai eucharistēsas edōken autois legōn</strong> — <em>and taking a cup and giving thanks he gave to them saying</em> — <em>Eucharistēsas</em> (having given thanks — from <em>eucharisteō</em>, the source of the word Eucharist) vs. the earlier <em>eulogēsas</em> (blessed) over the bread; the two forms of blessing-prayer are functionally synonymous in Jewish practice. <em>Piete ex autou pantes</em> (drink from it, all of you) — the <em>pantes</em> (all) is inclusive and imperative.</p>",
    "29": "<p><strong>ou mē piō ap\' arti ek toutou tou genēmatos tēs ampelou</strong> — <em>I will by no means drink from now from this produce of the vine</em> — <em>Ou mē</em> + aorist subjunctive = the strongest negation: absolutely not. <em>Ap\' arti</em> (from now, from this moment) — the eschatological vow of abstinence: Jesus will not drink wine again until the kingdom comes. <em>Heōs tēs hēmeras ekeinēs hotan auto pinō meth\' hymōn kainon en tē̄ basileiā̧ tou patros mou</em> — the future Messianic banquet (<em>kainon</em> = new, fresh) is the anticipated reunion.</p>",
    "30": "<p><strong>kai hymnēsantes exēlthon eis to oros tōn elaiōn</strong> — <em>and having sung a hymn they went out to the Mount of Olives</em> — <em>Hymneō</em> (to sing a hymn) — at Passover the <em>Hallel</em> psalms were sung: Pss 113-114 before the meal, 115-118 after. The <em>Hallelujah</em> psalms concluded the Passover observance. <em>Eis to oros tōn elaiōn</em> (to the Mount of Olives) — east of Jerusalem across the Kidron Valley.</p>",
    "31": "<p><strong>pantes hymeis skandalisthēsesthe en emoi en tē̄ nykti tautē̄</strong> — <em>all of you will fall away because of me this night</em> — <em>Skandalizō</em> (to cause to stumble, to fall away) — <em>en emoi</em> (because of me, on account of me) = Jesus himself will be the occasion of their stumbling. <em>Gegraptai gar</em> (for it is written) — Zech 13:7: <em>pataxō ton poimena kai diaskorpisthēsontai ta probata</em> (strike the shepherd and the sheep will be scattered).</p>",
    "32": "<p><strong>meta de to egerthēnai me proaxō hymas eis tēn Galilaian</strong> — <em>but after my being raised I will go before you to Galilee</em> — <em>To egerthēnai me</em> (my being raised — aorist passive infinitive) — the resurrection is assumed even in the prediction of scattering. <em>Proaxō</em> (I will go before, lead the way) — the risen Jesus will precede the disciples to Galilee, the place of mission origin. This anticipates the Great Commission scene (28:16-20).</p>",
    "33": "<p><strong>apokritheis de ho Petros eipen autō̄ ei kai pantes skandalisthēsontai en soi</strong> — <em>Peter answered: even if all fall away because of you</em> — Peter\xe2\x80\x99s <em>ei kai pantes</em> (even if all) — he dissociates himself from the group prediction. <em>Egō oudepote skandalisthēsomai</em> (I will never fall away) — <em>oudepote</em> (never, not at any time) is the strongest possible self-assertion.</p>",
    "34": "<p><strong>ephē autō̄ ho Iēsous amēn legō soi hoti en tautē̄ tē̄ nykti</strong> — <em>Jesus said: truly I say to you, in this very night</em> — The <em>amēn</em> introduction precedes a counter-prophecy. <em>Prin alektora phōnēsai tris aparnēsē̄ me</em> (before a cock crows you will deny me three times) — <em>alektōr</em> (rooster) — the third watch of the night (midnight to 3 AM) was called the <em>alektorophonia</em> (cock-crow watch). <em>Aparneomai</em> (to deny, disown, utterly refuse association with).</p>",
    "35": "<p><strong>kan dei me syn soi apothanein ou mē se aparnēsomai</strong> — <em>even if I must die with you I will by no means deny you</em> — <em>Kan</em> (even if — contracted from <em>kai ean</em>). <em>Dei</em> (it is necessary) + <em>apothanein</em> (to die, aorist infinitive). <em>Ou mē aparnēsomai</em> (I will by no means deny) — the double negative with aorist subjunctive: Peter\xe2\x80\x99s vow matches the force of Jesus\xe2\x80\x99 prediction. <em>Homoiōs de kai pantes hoi mathētai eipan</em> (similarly all the disciples also said) — collective overconfidence.</p>",
    "36": "<p><strong>tote erchetai met\' autōn ho Iēsous eis chōrion legomenon Gethsēmani</strong> — <em>then Jesus comes with them to a place called Gethsemane</em> — <em>Gethsēmani</em> (from Aramaic <em>gat-šĕmānê</em> = oil press) — an olive garden/press on the western slope of the Mount of Olives. <em>Kathisate autou heōs hou apelthōn ekei proseuxōmai</em> (sit here while I go there and pray) — Jesus separates the eight from the three.</p>",
    "37": "<p><strong>kai paralabōn ton Petron kai tous dyo huious Zebedaiou</strong> — <em>and taking Peter and the two sons of Zebedee</em> — The inner circle of three (Peter, James, John) who witnessed the Transfiguration (17:1) are now brought to witness the agony. <em>Ērxato lypeisthai kai adēmonein</em> (he began to be grieved and distressed) — <em>adēmoneō</em> (to be distressed, to be in anguish — a rare verb suggesting disorientation and anxiety) paired with <em>lypeō</em> (to grieve).</p>",
    "38": "<p><strong>perilypos estin hē psychē mou heōs thanatou</strong> — <em>my soul is deeply grieved to the point of death</em> — <em>Perilypos</em> (overwhelmed with grief, surrounded by sorrow — <em>peri</em> = around + <em>lypē</em> = grief) — the intensified compound. <em>Heōs thanatou</em> (to death, as far as death) — the grief is mortal in its intensity, echoing Ps 42:6,11 LXX. <em>Meinate hōde kai grēgoreite met\' emou</em> (stay here and watch with me) — the call for companionship in suffering.</p>",
    "39": "<p><strong>kai proelthōn mikron epesen epi prosōpon autou proseuchomenos</strong> — <em>going a little further he fell on his face praying</em> — <em>Epesen epi prosōpon autou</em> (fell upon his face) — full prostration, the most intense posture of supplication. <em>Pater ei dynaton estin parelthātō ap\' emou to potērion touto</em> (Father, if it is possible let this cup pass from me) — <em>ei dynaton</em> (if possible) — genuine submission to the Father\xe2\x80\x99s capacity to provide another way. <em>Plēn ouch hōs egō thelō all\' hōs sy</em> (yet not as I will but as you) — the subordination of the Son\xe2\x80\x99s desire to the Father\xe2\x80\x99s.</p>",
    "40": "<p><strong>kai erchetai pros tous mathētas kai heuriskei autous katheudōntas</strong> — <em>he comes to the disciples and finds them sleeping</em> — <em>Heuriskei</em> (present tense: finds) gives the discovery immediacy. <em>Kai legei tō̄ Petrō̧ houtōs ouk ischysate mian hōran grēgorēsai met\' emou</em> (and says to Peter: so you could not watch one hour with me?) — the address singles out Peter, who had just professed willingness to die with Jesus.</p>",
    "41": "<p><strong>grēgoreite kai proseuchesthe hina mē eiselthēte eis peirasmon</strong> — <em>watch and pray lest you enter into temptation/trial</em> — <em>Eiselthēte eis peirasmon</em> (enter into temptation/trial) — <em>peirasmos</em> (test, trial, temptation) echoes the Lord\xe2\x80\x99s Prayer petition (6:13). <em>To men pneuma prothumon hē de sarx asthenēs</em> (the spirit is willing/ready but the flesh is weak) — <em>prothumon</em> (eager, ready, forward-moving — from <em>pro</em> + <em>thymos</em> = passion rushing forward) contrasted with <em>asthenēs</em> (without strength, feeble).</p>",
    "42": "<p><strong>palin ek deuterou apelthōn prosēuxato</strong> — <em>going away again a second time he prayed</em> — <em>Ek deuterou</em> (a second time) marks the repetition explicitly. <em>Pater mou ei ou dynatai touto parelthein ean mē auto piō</em> (my Father, if this cannot pass unless I drink it) — the second prayer intensifies the submission: the condition shifts from <em>ei dynaton</em> (if possible) to <em>ei ou dynatai... ean mē auto piō</em> (if it cannot pass unless I drink it) — progressive acceptance of the cup.</p>",
    "43": "<p><strong>kai elthōn palin heurenautous katheudōntas</strong> — <em>coming again he found them sleeping</em> — <em>Ēsan gar autōn hoi ophthalmoi bebarēmenoi</em> (for their eyes were heavy, weighed down) — <em>bebarēmenoi</em> (perfect passive participle of <em>bareō</em> = to weigh down, burden) — the perfect describes a settled state of heaviness. The disciples cannot maintain even this minimal companionship.</p>",
    "44": "<p><strong>kai apheis autous palin apelthōn prosēuxato ek tritou</strong> — <em>leaving them again he went away and prayed a third time</em> — <em>Ek tritou</em> (a third time) — three prayers mirror the three denials Peter will make; the structural parallelism is notable. <em>Ton auton logon eipōn palin</em> (saying the same word again) — verbatim repetition of prayer language indicating sustained, consistent submission.</p>",
    "45": "<p><strong>tote erchetai pros tous mathētas kai legei autois katheudete loipon</strong> — <em>then he comes to the disciples and says: sleep on now</em> — <em>Katheudete loipon</em> (sleep on now, and take your rest) — the tone is ambiguous: either permission/irony (the moment of arrest is upon them) or a genuine brief rest before the arrest. <em>Idou ēggiken hē hōra</em> (behold the hour has drawn near) — <em>ēggiken</em> perfect: has drawn near and is now here.</p>",
    "46": "<p><strong>egeiresthe agōmen</strong> — <em>rise, let us go</em> — <em>Egeirō</em> (to raise, arouse) aorist imperative + <em>agōmen</em> (let us go) present subjunctive — a decisive call to action. <em>Idou ēggiken ho paradidous me</em> (behold the one handing me over has drawn near) — the same perfect <em>ēggiken</em>: Judas\xe2\x80\x99 arrival coincides with the announcement of the hour\xe2\x80\x99s coming.</p>",
    "47": "<p><strong>kai eti autou lalountos idou Ioudas</strong> — <em>and while he was still speaking, behold Judas</em> — <em>Eti autou lalountos</em> (genitive absolute: while he was still speaking) — the immediacy is dramatic; the prediction and its fulfillment are simultaneous. <em>Heis tōn dōdeka ēlthen</em> (one of the Twelve came) — the repeated designation <em>heis tōn dōdeka</em> (one of the Twelve) sharpens the betrayal\xe2\x80\x99s horror: intimacy makes the act worse.</p>",
    "48": "<p><strong>ho de paradidous auton edōken autois sēmeion</strong> — <em>the one betraying him had given them a sign</em> — <em>Ho paradidous</em> (the one handing over/betraying — present active participle, almost a technical title for Judas). <em>Sēmeion</em> (a sign, signal) — a pre-arranged identification signal. <em>Hon an philēsō autos estin</em> (whoever I kiss, he is the one) — <em>philēsō</em> (aorist subjunctive of <em>phileō</em> = to love, kiss as a greeting) — a kiss (<em>philēma</em>) was the standard greeting between teacher and student.</p>",
    "49": "<p><strong>kai eutheōs proselthōn tō̄ Iēsou eipen chaire Rhabbi</strong> — <em>and immediately approaching Jesus he said: greetings, Rabbi</em> — <em>Chaire</em> (hail, rejoice, greetings — the standard Greek greeting). <em>Rhabbi</em> again (cf. 26:25) — not <em>kyrie</em>. <em>Kai katephilēsen auton</em> (and kissed him warmly) — <em>kataphileō</em> (intensive form with <em>kata-</em>: to kiss affectionately, to kiss repeatedly) — the intensified compound makes the betrayal\xe2\x80\x99s tenderness more grotesque.</p>",
    "50": "<p><strong>ho de Iēsous eipen autō̄ hetaire eph\' ho parei</strong> — <em>Jesus said to him: friend, for what purpose are you here?</em> — <em>Hetaire</em> (companion — the distancing form; third use in Matthew: 20:13; 22:12) — gentle but not intimate. <em>Eph\' ho parei</em> (for what purpose you have come) — traditionally taken as a question but may be a statement: <em>do what you have come for</em>. <em>Tote proselthontes epebalon tas cheiras epi ton Iēsoun kai ekratēsan auton</em> (then approaching they laid hands on Jesus and seized him).</p>",
    "51": "<p><strong>kai idou heis tōn meta Iēsou ekteinas tēn cheira apespasen tēn machairan autou</strong> — <em>behold one of those with Jesus drew his sword</em> — <em>Apespasen</em> (drew, pulled out — aorist of <em>aposoaō</em>) the sword. <em>Kai pataxas ton doulon tou archiereōs apheilen autou to ōtion</em> (and striking the servant of the high priest cut off his ear) — <em>ōtion</em> (diminutive: the ear; <em>ous</em> = ear; John 18:10 names him Malchus and the striker as Peter).</p>",
    "52": "<p><strong>tote legei autō̄ ho Iēsous apostrepson tēn machairan sou eis ton topon autēs</strong> — <em>then Jesus says: put your sword back into its place</em> — <em>Apostrepō</em> (to turn back, return) imperative — a direct command. <em>Pantes gar hoi labontes machairan en machairā̄ apolountai</em> (for all those who take the sword by the sword will perish) — a proverbial statement: <em>en machairā̄</em> (by the sword, instrumental dative) — violence self-propagates until it consumes its agents.</p>",
    "53": "<p><strong>ē dokeis hoti ou dynamai parakalesai ton patera mou</strong> — <em>do you think I cannot call on my Father?</em> — <em>Parakalesai</em> (to call alongside, appeal to, summon) — Jesus could appeal to the Father for rescue. <em>Kai parastēsei moi arti pleio ē dōdeka legiones angelōn</em> (and he would at once provide me more than twelve legions of angels) — <em>legiōn</em> (Roman legion = ~6,000 soldiers) — twelve legions = ~72,000 angels. The capacity for divine rescue exists; the choice not to use it is itself the obedience.</p>",
    "54": "<p><strong>pōs oun plērōthōsin hai graphai hoti houtōs dei genesthai</strong> — <em>how then would the scriptures be fulfilled that it must happen this way?</em> — <em>Plērōthōsin</em> (be fulfilled, aorist passive subjunctive) — the fulfillment of scripture is the governing constraint on Jesus\xe2\x80\x99 actions. <em>Dei genesthai</em> (it must happen, it is necessary to happen) — the divine <em>dei</em> of eschatological necessity.</p>",
    "55": "<p><strong>hōs epi lēstēn exēlthate meta machairōn kai xylōn syllabein me</strong> — <em>as against a bandit you came out with swords and clubs to arrest me</em> — <em>Lēstēs</em> (bandit, robber, insurgent — the same word as Barabbas and the crucified men) — the armed arrest befits a violent criminal, not a teacher. <em>Kath\' hēmeran en tō̄ hierō̄ ekathezomēn didaskōn</em> (daily I was sitting in the temple teaching) — <em>ekathezomēn</em> imperfect: continuous daily public presence; no secrecy required arrest in the dark.</p>",
    "56": "<p><strong>touto de holon gegonen hina plērōthōsin hai graphai tōn prophētōn</strong> — <em>all this has happened so that the writings of the prophets might be fulfilled</em> — <em>Touto de holon</em> (but all this) — the entire arrest sequence is enclosed within divine purpose. <em>Tote hoi mathētai pantes aphentes auton ephygon</em> (then all the disciples leaving him fled) — <em>aphentes</em> (having left behind) fulfills the scattering prediction of v.31 and Zech 13:7.</p>",
    "57": "<p><strong>hoi de kratēsantes ton Iēsoun apēgagon pros Kaiaphan</strong> — <em>those who had seized Jesus led him away to Caiaphas</em> — <em>Apēgagon</em> (led away, aorist of <em>apagō</em> = to lead off) — the judicial transfer. <em>Hopou hoi grammateis kai hoi presbyteroi synēchthēsan</em> (where the scribes and elders were assembled) — the Sanhedrin in extraordinary night session.</p>",
    "58": "<p><strong>ho de Petros ēkolouthei autō̄ makrothen</strong> — <em>Peter was following him from a distance</em> — <em>Makrothen</em> (from a distance, afar) — the adverb signals Peter\xe2\x80\x99s ambivalence: he follows but maintains protective distance. <em>Heōs tēs aulēs tou archiereōs</em> (as far as the courtyard of the high priest). <em>Kai eiselthōn esō ekathēto meta tōn hypēretōn</em> (and entering inside he sat with the officers) — <em>hypēretai</em> (officers, attendants, servants) = the temple police/Sanhedrin staff.</p>",
    "59": "<p><strong>hoi de archiereis kai to synedrion holon ezētoun pseudomartyrian kata tou Iēsou</strong> — <em>the chief priests and the whole council were seeking false testimony against Jesus</em> — <em>Pseudomartyria</em> (false testimony — <em>pseudēs</em> + <em>martyria</em>) — Matthew characterizes the testimony as false from the outset. <em>Hopōs auton thanatōsōsin</em> (in order that they might put him to death) — <em>thanatōsōsin</em> (aorist subjunctive of <em>thanatoō</em> = to put to death, to cause to die) — capital intent governs the proceedings.</p>",
    "60": "<p><strong>kai ouch heuron pollōn proselthontōn pseudomartyrōn</strong> — <em>and did not find it, though many false witnesses came forward</em> — The negative <em>ouch heuron</em> (did not find) implies that the testimony was insufficient or contradictory (cf. Mark 14:56: <em>hai martyriai ouk ēsan isai</em> = the testimonies were not consistent). Two witnesses were required by Deut 17:6; 19:15 for capital charges.</p>",
    "61": "<p><strong>houtos ephē dynamai katalysai ton naon tou theou</strong> — <em>this one said: I am able to tear down the temple of God</em> — The false witnesses misquote Jesus\xe2\x80\x99 statement (cf. John 2:19 where Jesus said <em>lysate</em> = you destroy); they substitute <em>dynamai katalysai</em> (I am able to tear down — first person boast) for Jesus\xe2\x80\x99 second-person conditional. <em>Kai dia triōn hēmerōn oikodomēsai</em> (and in three days to rebuild it).</p>",
    "62": "<p><strong>kai anastas ho archiereus eipen autō̄ ouden apokrinou</strong> — <em>the high priest stood up and said: do you answer nothing?</em> — <em>Anastas</em> (having stood up, rising) signals judicial importance. <em>Ti houtoi sou katamartyrousi</em> (what these testify against you?) — the high priest presses for a response that would either condemn or acquit.</p>",
    "63": "<p><strong>ho de Iēsous esiōpa</strong> — <em>Jesus was silent</em> — <em>Siopaō</em> (imperfect: was remaining silent, maintained silence) — the fulfillment of Isa 53:7 (<em>hōs probaton epi sphagēn</em>: as a sheep before its shearers is silent). The silence is deliberate and meaningful, not inability. The high priest then invokes the divine oath: <em>exorkizō se kata tou theou tou zōntos</em> (I adjure you by the living God) — a formal oath-charge compelling testimony.</p>",
    "64": "<p><strong>plēn legō hymin ap\' arti opsesthe ton huion tou anthrōpou</strong> — <em>but I tell you, from now you will see the Son of Man</em> — <em>Sy eipas</em> (you have said it) first affirms the title, then adds <em>plēn</em> (nevertheless, but I tell you) with a further disclosure. <em>Kathēmenon ek dexiōn tēs dynameōs</em> (sitting at the right hand of Power) — <em>hē dynamis</em> (Power = divine name by circumlocution). <em>Kai erchomenon epi tōn nephelōn tou ouranou</em> quotes Dan 7:13 — the coming with clouds of heaven.</p>",
    "65": "<p><strong>tote ho archiereus dierrēxen ta himatia autou</strong> — <em>then the high priest tore his garments</em> — <em>Diarrēgnymi</em> (to tear apart, rip through) the garments — the prescribed gesture upon hearing blasphemy (<em>bēasphēmia</em>) in rabbinic law (<em>m. Sanh.</em> 7:5). <em>Blasphēmēsen</em> (he has blasphemed) — the accusation; the high priest\xe2\x80\x99s own judgment (<em>ti eti chreian echomen martyrōn</em> = what further need have we of witnesses?) uses the first-person plural, implicating the whole council.</p>",
    "66": "<p><strong>ti hymin dokei</strong> — <em>what do you think?</em> — The judicial vote-request. <em>Hoi de apokrithentes eipan enochos thanatou estin</em> (answering they said: he is liable to death) — <em>Enochos</em> (liable to, guilty of — genitive of charge) + <em>thanatou</em> (death) — a capital verdict rendered by the full council.</p>",
    "67": "<p><strong>tote eneptysan eis to prosōpon autou</strong> — <em>then they spat in his face</em> — <em>Emptyo eis prosōpon</em> (to spit into the face) — the deepest contempt gesture in ancient culture (Num 12:14; Job 30:10). <em>Ekolaphisan auton</em> (they struck him with their fists) — <em>kolaphizō</em> (to strike with the knuckles). <em>Hoi de errapisan</em> (others slapped him) — <em>rhapizō</em> (to slap with an open hand).</p>",
    "68": "<p><strong>prophēteuson hēmin christe tis estin ho paisas se</strong> — <em>prophesy to us, Christ, who is the one who struck you?</em> — <em>Prophēteuson</em> (prophesy! — aorist imperative) + <em>christe</em> (Christ! — the messianic title used as mockery) — the taunt forces a demonstration of the very messianic gift he claimed. The guards who struck him blindfolded him first (Mark 14:65; Luke 22:64), making identification impossible by natural means.</p>",
    "69": "<p><strong>ho de Petros ekathēto exō en tē̄ aulē̄</strong> — <em>Peter was sitting outside in the courtyard</em> — The narrative shifts back to Peter (cf. v.58). <em>Kai prosēlthen autō̄ mia paidiskē</em> (and a servant girl came to him) — <em>paidiskē</em> (a young female slave, a servant girl) — the contrast between the accused Jesus inside and the accuser\xe2\x80\x99s servant outside is structurally deliberate.</p>",
    "70": "<p><strong>ho de ērnēsato emprosthen pantōn</strong> — <em>he denied before all</em> — <em>Arneomai</em> (to deny, to disavow) — the verb for denial that Jesus predicted. <em>Ouk oida ti legeis</em> (I do not know what you are saying) — the first denial is categorical ignorance: <em>oida</em> (to know) negated.</p>",
    "71": "<p><strong>exelthonta de auton eis ton pylōna</strong> — <em>going out to the gateway</em> — Peter moves to the exit area; another servant girl (<em>allē paidiskē</em>) makes a more direct claim: <em>kai houtos ēn meta Iēsou tou Nazōraiou</em> (this one was with Jesus the Nazarene) — <em>meta</em> (with) = association/discipleship.</p>",
    "72": "<p><strong>kai palin ērnēsato meta horkou</strong> — <em>again he denied with an oath</em> — <em>Meta horkou</em> (with an oath) — the escalation from simple denial (v.70) to an oath-reinforced denial. <em>Hoti ouk oida ton anthrōpon</em> (that I do not know the man) — <em>ton anthrōpon</em> (the man) — Peter distances himself with the indefinite reference rather than naming Jesus.</p>",
    "73": "<p><strong>kai hē lalia sou dēlon se poiei</strong> — <em>your speech makes you evident</em> — <em>Lalia</em> (speech, way of speaking, dialect) — the Galilean accent or dialect was distinctive to Jerusalem ears. <em>Dēlon se poiei</em> (makes you manifest, obvious) — the very speech that denies association betrays it. <em>Kai gar Galilaios ei</em> (for indeed you are a Galilean).</p>",
    "74": "<p><strong>tote ērxato anathematizein kai omnynai hoti ouk oida ton anthrōpon</strong> — <em>then he began to call down curses and to swear: I do not know the man</em> — <em>Anathematizō</em> (to call down a curse, to invoke a curse on oneself) — invoking divine judgment on oneself if the statement is false. <em>Omnymi</em> (to swear an oath) — the third denial combines a self-curse and an oath, the most intense verbal repudiation possible. <em>Kai eutheōs alektōr ephōnēsen</em> (and immediately a cock crowed) — the fulfillment of 26:34.</p>",
    "75": "<p><strong>kai emnēsthē ho Petros tou rhēmatos Iēsou</strong> — <em>Peter remembered the word of Jesus</em> — <em>Emnēsthē</em> (aorist passive of <em>mimnēskomai</em> = to remember) — the memory is involuntary, brought on by the cock\xe2\x80\x99s crow. <em>Tou rhēmatos</em> (the word, the statement) — specific recall of the prediction. <em>Kai exelthōn exō eklausen pikrōs</em> (and going outside he wept bitterly) — <em>pikrōs</em> (bitterly, from <em>pikros</em> = sharp, piercing) — the adverb intensifies the weeping into anguished grief.</p>"
  }
}

comm = load_comm('mkt-original', 'matthew')
merge_comm(comm, NEW_DATA)
save_comm('mkt-original', 'matthew', comm)

print('Done.')
